#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2Logic.Entities;
using PVZEngine.Auras;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Buffs.Enemies
{
    [AutoBuffDefinition(VanillaBuffNames.Enemy.darkMatterInvisible)]
    public class DarkMatterInvisibleBuff : BuffDefinition
    {
        public DarkMatterInvisibleBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(ColorModifier.Multiply(EngineEntityProps.TINT, new Color(1, 1, 1, 0)));
            AddModifier(new BooleanModifier(LogicEntityProps.SHOW_HEIGHT_INDICATOR, false));
            AddModifier(new BooleanModifier(LogicEntityProps.HIDE_HP_BAR, true));
            AddModifier(new BooleanModifier(LogicEntityProps.SHADOW_HIDDEN, true));
            AddAura(new ArmorInvisibleAura());
            AddTrigger(LevelCallbacks.POST_GAME_OVER, PostGameOverCallback);
        }
        private void PostGameOverCallback(LevelCallbacks.PostGameOverParams param, CallbackResult result)
        {
            var level = param.level;
            foreach (var entity in level.FindEntities(e => e.HasBuff<DarkMatterInvisibleBuff>()))
            {
                entity.RemoveBuffs<DarkMatterInvisibleBuff>();
            }
        }
        public class ArmorInvisibleAura : AuraEffectDefinition
        {
            public ArmorInvisibleAura() : base(VanillaBuffID.Armor.darkMatterArmorInvisible)
            {
            }

            public override void GetAuraTargets(AuraEffect auraEffect, List<IBuffTarget> results)
            {
                var entity = auraEffect.Source.GetEntity();
                if (entity == null)
                    return;
                foreach (var slot in entity.GetActiveArmorSlots())
                {
                    var armor = entity.GetArmorAtSlot(slot);
                    if (armor == null)
                        continue;
                    results.Add(armor);
                }
            }
        }
    }
}
